-- Enable UUID extension
CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Drop tables if they exist (for easy resetting)
DROP TABLE IF EXISTS proposals CASCADE;
DROP TABLE IF EXISTS client_needs CASCADE;
DROP TABLE IF EXISTS smls CASCADE;
DROP TABLE IF EXISTS users CASCADE;

-- Create Users Table
CREATE TABLE users (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    email VARCHAR(255) UNIQUE NOT NULL,
    password_hash VARCHAR(255) NOT NULL,
    role VARCHAR(50) NOT NULL CHECK (role IN ('client', 'admin')),
    company_name VARCHAR(255),
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Create SMLs Table
CREATE TABLE smls (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    name VARCHAR(255) NOT NULL,
    category VARCHAR(255) NOT NULL,
    description TEXT NOT NULL,
    base_model_type VARCHAR(100) NOT NULL,
    is_active BOOLEAN DEFAULT TRUE,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Create Client Needs Table
CREATE TABLE client_needs (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    client_id UUID REFERENCES users(id) ON DELETE CASCADE,
    problem_description TEXT NOT NULL,
    expected_users_concurrent INTEGER NOT NULL,
    data_sensitivity VARCHAR(50) NOT NULL CHECK (data_sensitivity IN ('low', 'medium', 'high', 'critical')),
    use_cases_priority JSONB NOT NULL,
    current_ia_pain_points TEXT,
    status VARCHAR(50) NOT NULL DEFAULT 'submitted' CHECK (status IN ('draft', 'submitted', 'reviewed', 'proposal_generated')),
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- Create Proposals Table
CREATE TABLE proposals (
    id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
    client_need_id UUID REFERENCES client_needs(id) ON DELETE CASCADE UNIQUE,
    recommended_sml_ids JSONB NOT NULL, -- Array of UUIDs
    recommended_nodo_type VARCHAR(50) NOT NULL CHECK (recommended_nodo_type IN ('Starter', 'Enterprise', 'Sovereign', 'Custom')),
    estimated_fixed_cost_usd NUMERIC(10, 2) NOT NULL,
    estimated_amortization_months INTEGER NOT NULL,
    proposal_details TEXT NOT NULL,
    hardware_specs JSON DEFAULT '{}',
    status VARCHAR(50) DEFAULT 'pending' CHECK (status IN ('pending', 'accepted', 'rejected')),
    created_at TIMESTAMPTZ DEFAULT NOW(),
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

